    #[test]
    fn para_subtree_ids() {
        let (e, root) = sample();
        // Para gives (Id, A) — the Id is the original subtree handle.
        // Use it to check that the root's direct children are accessible.
        let (left_id, right_id) = e.fold_with_ids(root, |node: E<(Id, (Id, Id))>| match node {
            E::Lit(_) => (Id(usize::MAX), Id(usize::MAX)),
            E::Add((lid, _), (rid, _)) | E::Mul((lid, _), (rid, _)) => (lid, rid),
            E::Neg((cid, _)) => (cid, cid),
        });
        // Root is Mul(Add(...), Neg(...)) — check we got valid, distinct ids
        assert_ne!(left_id, right_id);
        assert_eq!(show(&e, left_id), "(1 + 2)");
        assert_eq!(show(&e, right_id), "(-3)");
    }

