    #[test]
    fn ana_build_tree() {
        // Unfold: n -> Add(n-1, n-1) until n==0 -> Lit(1)
        let mut arena = Expr::new();
        let root = unfold(&mut arena, 3u32, |n| {
            if n == 0 {
                (E::Lit(1), vec![])
            } else {
                (E::Add(0, 0), vec![n - 1, n - 1])
            }
        });
        let val = arena.fold(root, |node: E<i64>| match node {
            E::Lit(n) => n,
            E::Add(a, b) => a + b,
            E::Mul(a, b) => a * b,
            E::Neg(a) => -a,
        });
        assert_eq!(val, 8); // 2^3
    }

    #[test]
    fn ana_deep_chain_no_stack_overflow() {
        // A chain of 1_000_000 Neg nodes — would blow the stack if recursive
        let mut arena = Expr::new();
        let root = unfold(&mut arena, 1_000_000u32, |n| {
            if n == 0 {
                (E::Lit(42), vec![])
            } else {
                (E::Neg(0), vec![n - 1])
            }
        });
        // Even depth: 1_000_000 negations cancel out
        let val = arena.fold(root, |node: E<i64>| match node {
            E::Lit(n) => n,
            E::Neg(a) => -a,
            E::Add(a, b) => a + b,
            E::Mul(a, b) => a * b,
        });
        assert_eq!(val, 42);
    }

