    #[test]
    fn fold_with_original_sees_node() {
        let (e, root) = sample();
        // fold_with_original: count nodes, but double-count Neg nodes
        let count = e.fold_with_original(root, |orig: &E<usize>, node: E<usize>| {
            let base = match node {
                E::Lit(_) => 1,
                E::Add(a, b) | E::Mul(a, b) => 1 + a + b,
                E::Neg(a) => 1 + a,
            };
            match orig {
                E::Neg(_) => base + 1, // extra count for Neg
                _ => base,
            }
        });
        // Normal size is 6, one Neg node adds 1 extra
        assert_eq!(count, 7);
    }

    #[test]
    fn transform_down_pre_order() {
        // Build Neg(Neg(Lit(5)))
        let mut e = Expr::new();
        let five = lit(&mut e, 5);
        let n1 = neg(&mut e, five);
        let root = neg(&mut e, n1);

        // transform_down: replace Neg(x) with Mul(x, x) pre-order
        let (e2, r2) = e.rewrite_down(root, |node| match node {
            E::Neg(inner) => E::Mul(inner, inner),
            other => other,
        });
        // Pre-order: outer Neg(Neg(Lit(5))) -> Mul(Neg(Lit(5)), Neg(Lit(5)))
        // Then inner Negs also rewritten -> Mul(Mul(Lit(5),Lit(5)), Mul(Lit(5),Lit(5)))
        let val = e2.fold(r2, |node: E<i64>| match node {
            E::Lit(n) => n,
            E::Neg(a) => -a,
            E::Add(a, b) => a + b,
            E::Mul(a, b) => a * b,
        });
        assert_eq!(val, 625); // 5^4
    }

